[37] يُنظر: ((تفسير ابن كثير)) (6/9)، ((نظم الدرر)) للبقاعي (13/207)، ((تفسير الشوكاني)) (4/8). قال الشنقيطي: (اعلَمْ أنَّ العلماءَ اختَلَفوا فِي جَوازِ نِكاحِ العفِيفِ الزَّانِيةَ، ونِكاحِ العفيفةِ الزَّانِيَ، فذَهَب جَماعَةٌ مِن أهلِ العلمِ؛ منهم الأئِمَّةُ الثَّلاثةُ إلى جوازِ نِكاحِ الزَّانِيةِ مع الكراهةِ التَّنْزيهيَّةِ عندَ مالِكٍ وأصحابِه، ومَن وافَقَهم). ((أضواء البيان)) (5/418). ويُنظر: ((البحر الرائق)) لابن نجيم (3/114)، ((شرح مختصر خليل)) للخرشي، (3/172)، ((الحاوي الكبير)) للماوَرْدي (9/189). وقال الشوكاني: (وقيل: هو مكروهٌ فقطْ [أي: نكاح الزواني]، وعَبَّر بالتَّحريمِ عن كراهةِ التَّنزيهِ مُبالغةً في الزَّجْرِ). ((تفسير الشوكاني)) (4/8). وقال الشنقيطي: (وهنا قد يرِدُ سؤالٌ، وهو كيفَ سوَّغ هؤلاء الأئمةُ الأجِلَّاءُ للمسلمِ العفيفِ مقاربةَ الزانيةِ بالزَّواجِ منها، وهي زانيةٌ خبيثةٌ خسيسةٌ؟ والجوابُ: أنَّ هؤلاء الأئمةَ لم يُجيزوا له ذلك على أن يتركَها وشأنَها، وإنَّما جوَّزوا له ذلك معَ المحافظةِ عليها، والضربِ على يدِها وزجرِها، وإذا وقَع منها ما لا يَنبَغي مِن ارتكابِ الفاحشةِ، وهو لا يدري وقد عمِل ما يقدرُ عليه مِن الاحتياطاتِ التي تحولُ بينها وبينَ ذلك فلا حرجَ عليه، وتكونُ معَه على حدِّ قولِ القائلِ: اجْتَنِ الثِّمارَ، وألْقِ الخشبةَ في النارِ). ((تفسير سورة النور)) (ص: 37). وقال ابن تيميَّة: (والذين لم يَعملوا بهذه الآيةِ ذكَروا لها تأويلًا ونَسخًا؛ أمَّا التأويلُ فقالوا: المرادُ بالنِّكاحِ الوَطءُ... وأمَّا النَّسخُ فقال سعيدُ بنُ المسيِّبِ وطائفةٌ: نسَخَها قَولُه: وَأَنْكِحُوا الْأَيَامَى مِنْكُمْ
[النور: 32]
). وبيَّن ضَعفَ هذا القولِ. يُنظر: ((الفتاوى الكبرى)) لابن تيمية (3/178). وذهب الحنابلةُ إلى أنَّه يَحرُمُ الزواجُ بالزانيةِ حتى تَتوبَ. يُنظر: ((المبدع في شرح المقنع)) لبرهان الدين ابن مفلح (6/138)، ((الشرح الممتع)) لابن عثيمين (12/138).

[115] قال البِقَاعيُّ: (الْمُحْصَنَاتِ جمْعُ مُحصَنةٍ، وهي هنا المُسلِمةُ، الحُرَّةُ، المُكلَّفةُ، العَفيفةُ). ((نظم الدرر)) (13/214). وقال الرازيُّ: (ظاهِرُ الآيةِ يَتناوَلُ جميعَ العفائفِ؛ سواءٌ كانت مُسلمةً أو كافرةً، وسواءٌ كانت حُرَّةً أو رقيقةً، إلَّا أنَّ الفُقهاءَ قالوا: شرائطُ الإحصانِ خمْسةٌ: الإسلامُ، والعقْلُ، والبُلوغُ، والحُرِّيةُ، والعِفَّةُ مِن الزِّنا). ((تفسير الرازي)) (23/323). وهذه الشرائطُ الخمسةُ اتفقَتْ عليها المذاهبُ الفقهيَّةُ الأربعةُ، وخالَف الحنابلةُ في البلوغِ؛ فقالوا: لا يُشترَطُ في المَقذوفِ البلوغُ، بل أن يَكونَ مِثلُه يَطأُ أو يُوطأُ. يُنظر: ((بدائع الصنائع)) للكاساني (7/40)، ((شرح مختصر خليل)) للخرشي (8/86)، ((نهاية المحتاج)) للرملي (7/109،437)، ((كشاف القناع)) للبُهُوتي (6/105). وقال القرطبيُّ: (قذْفُ الرِّجالِ داخلٌ في حُكمِ الآيةِ بالمعنى، وإجماعِ الأُمَّةِ على ذلك... وحكى الزَّهراويُّ أنَّ المعنى: الأنفُسَ المُحْصناتِ؛ فهي بلَفْظِها تعُمُّ الرِّجالَ والنِّساءَ، ويدُلُّ على ذلك قولُه: وَالْمُحْصَنَاتُ مِنَ النِّسَاءِ
[النساء: 24]
). ((تفسير القرطبي)) (12/172). وممَّن حكى الإجماعَ أيضًا: ابنُ كثيرٍ، والشنقيطيُّ. يُنظر: ((تفسير ابن كثير)) (6/13)، ((أضواء البيان)) للشنقيطي (5/431).

[1091] ممَّن اختار أنَّ المرادَ بقَولِه: أَلَمْ تَرَ أي: ألم تَعلَمْ: مقاتلُ بنُ سليمانَ، والرازيُّ، والقرطبيُّ، والبيضاويُّ، والنسفيُّ، وابن جُزَي، والشوكانيُّ، وابنُ عثيمينَ. يُنظر: ((تفسير مقاتل بن سليمان)) (3/203)، ((تفسير الرازي)) (24/401)، ((تفسير القرطبي)) (12/286)، ((تفسير البيضاوي)) (4/110)، ((تفسير النسفي)) (2/510)، ((تفسير ابن جزي)) (2/72)، ((تفسير الشوكاني)) (4/47)، ((تفسير ابن عثيمين - سورة النور)) (ص: 284). ويُنظر: أيضًا: ((تفسير ابن جرير)) (17/333)، ((الهداية الى بلوغ النهاية)) لمكِّي (8/5128). قال ابنُ عثيمين: (هل هذه الرُّؤيةُ بَصَريَّةٌ أو عِلميَّةٌ؟ ... الأَولى: أن تكونَ عِلميَّةً، يعني: ألمْ تَعلَمْ، سواءٌ كان عِلمُك عن طريقِ المُشاهَدةِ بالبَصَرِ، أو عن طريقِ السَّمعِ بالأُذُنِ، أو عن طريقِ الاستِنتاجِ بالعَقلِ والتَّفكيرِ، هذه الثَّلاثةُ هي طُرُقُ العِلمِ، كما قال الله عزَّ وجَلَّ: إِنَّ السَّمْعَ وَالْبَصَرَ وَالْفُؤَادَ كُلُّ أُولَئِكَ كَانَ عَنْهُ مَسْئُولًا
[الإسراء: 36]
). ((تفسير ابن عثيمين - سورة النور)) (ص: 284). وقال الشوكاني: (والخطابُ لكلِّ مَنْ له أهليَّةُ النَّظرِ، أو للرَّسولِ صلَّى الله عليه وسَلَّم، وقد عَلِمه مِنْ جهةِ الاستِدلالِ). ((تفسير الشوكاني)) (4/47). ممَّن اختار أنَّ المُخاطَبَ هو النَّبيُّ صلَّى اللهُ عليه وسلَّم: ابنُ جرير، ومكي، والنسفي. يُنظر: ((تفسير ابن جرير)) (17/333)، ((الهداية الى بلوغ النهاية)) لمكي (8/5128)، ((تفسير النسفي)) (2/510). وممَّن اختار العُمومَ: القرطبيُّ، وابنُ عثيمين. يُنظر: ((تفسير القرطبي)) (12/286)، ((تفسير ابن عثيمين - سورة النور)) (ص: 284). قال ابنُ عثيمين: (قَولُه: أَلَمْ تَرَ أَنَّ اللَّهَ يُسَبِّحُ يعني: قد رأيتَ، لكِنْ هل الخِطابُ للرَّسولِ صلَّى اللهُ عليه وسلَّم، أو لكُلِّ مَن يتأتَّى خِطابُه؟ الظَّاهِرُ: العُمومُ. أَلَمْ تَرَ أيُّها المخاطَبُ، لا أيُّها النبيُّ؛ لأنَّ ذلك أشمَلُ وأعَمُّ). ((تفسير ابن عثيمين- سورة النور)) (ص: 284).

[1105] يُنظر: ((نظم الدرر)) للبقاعي (13/292)، ((تفسير الشوكاني)) (4/49)، ((تفسير السعدي)) (ص: 571)، ((تفسير ابن عاشور)) (18/261، 262). قال الرازي: (في هذه الآيةِ قولان؛ أحدُهما: أنَّ في السَّماءِ جِبالًا مِن بَرَدٍ خلَقَها الله تعالى كذلك، ثمَّ يُنزِّلُ منها ما شاء. وهذا القَولُ عليه أكثَرُ المفَسِّرينَ، قال مجاهدٌ والكلبيُّ: جبالٌ مِن برَدٍ في السَّماءِ. والقولُ الثاني: أنَّ السَّماءَ هو الغَيمُ المرتفِعُ على رؤوسِ النَّاسِ؛ سُمِّيَ بذلك لسُمُوِّه وارتفاعِه، وأنَّه تعالى أنزلَ مِن هذا الغيمِ -الذي هو سماءٌ- البَرَدَ، وأراد بقولِه: مِنْ جِبَالٍ السَّحابَ العِظامَ؛ لأنَّها إذا عَظُمت أشبَهَت الجبالَ، كما يقالُ: فلانٌ يملِكُ جِبالًا مِن مالٍ، ووُصِفَت بذلك توسُّعًا. وذهبوا إلى أنَّ البَرَدَ ماءٌ جامِدٌ خلَقَه الله تعالى في السَّحابِ، ثمَّ أنزله إلى الأرضِ). ((تفسير الرازي)) (24/405). وممَّن ذهَب إلى القولِ الأوَّلِ وأنَّ هذه الجبالَ مِن بَرَدٍ: يحيى بنُ سلام، والزجَّاج، والواحدي، وأبو حيان، والعليمي، وابن عثيمين. يُنظر: ((تفسير يحيى بن سلام)) (1/455)، ((معاني القرآن)) للزجاج (4/49)، ((الوسيط)) للواحدي (3/324) ((تفسير أبي حيان)) (8/57)، ((تفسير العليمي)) (4/547)، ((تفسير ابن عثيمين - سورة النور)) (ص: 297). وممَّن ذهَب إلى القولِ الثاني في الجملةِ: البِقَاعيُّ، ومحمد رشيد رضا، والسعدي، وابن عاشور. يُنظر: ((نظم الدرر)) للبقاعي (13/292)، ((تفسير المنار)) لمحمد رشيد رضا (8/416)، ((تفسير السعدي)) (ص: 571)، ((تفسير ابن عاشور)) (18/261، 262). وقال محمد رشيد رضا: (لا مانِعَ مِنْ جَعْلِ السَّماءِ فيها عَيْنَ السَّحابِ، ولعلَّ الأظهَرَ أنْ يُرادَ بها جهةُ العلوِّ الَّتي يكونُ فيها السَّحابُ؛ كقولِه: فَيَبْسُطُهُ فِي السَّمَاءِ كَيْفَ يَشَاءُ
[الروم: 48]
). ((تفسير المنار)) (8/416). ويُنظر: ((تفسير الشوكاني)) (4/49).

[1108] يُنظر: ((تفسير ابن جرير)) (17/339)، ((تفسير القرطبي)) (12/290)، ((تفسير البيضاوي)) (4/111)، ((تفسير ابن كثير)) (6/73)، ((تفسير السعدي)) (ص: 571)، ((تفسير ابن عاشور)) (18/264). ممَّن اختار أنَّ المرادَ بتقلُّبِ اللَّيلِ والنَّهارِ: اختِلافُهما؛ فيأتي باللَّيلِ ويَذهبُ بالنهارِ، ثمَّ يأتي بالنهارِ ويَذهبُ باللَّيلِ: مقاتلُ بن سليمان، وابنُ جرير، والسمرقنديُّ، والثعلبيُّ، والواحديُّ، وابنُ عطيَّة، وابنُ الجوزي، والخازنُ، وابنُ جُزَي، وجلالُ الدِّينِ المحلِّيُّ، والشوكانيُّ. يُنظر: ((تفسير مقاتل بن سليمان)) (3/204)، ((تفسير ابن جرير)) (17/339)، ((تفسير السمرقندي)) (2/517)، ((تفسير الثعلبي)) (7/112)، ((الوسيط)) للواحدي (3/324)، ((تفسير ابن عطية)) (4/190)، ((تفسير ابن الجوزي)) (3/301)، ((تفسير الخازن)) (3/301)، ((تفسير ابن جزي)) (2/73)، ((تفسير الجلالين)) (ص: 466)، ((تفسير الشوكاني)) (4/50). وممَّن قال بهذا القولِ مِن السَّلف: السُّدِّيُّ. يُنظر: ((تفسير ابن أبي حاتم)) (8/2619). وممَّن اختار في الجملةِ أنَّ المرادَ: أخْذُ كلِّ واحِدٍ منهما مِن صاحِبِه: يحيى بنُ سلام، وابن أبي زمنين، وابن كثير. يُنظر: ((تفسير يحيى بن سلام)) (1/455)، ((تفسير ابن أبي زمنين)) (3/241)، ((تفسير ابن كثير)) (6/73). وممَّن اختار أنَّ المرادَ: يُعاقِبُ بيْن اللَّيلِ والنهارِ، ويُخالِفُ بيْنهما بالطُّولِ والقِصَرِ: الزمخشريُّ، والنسفي، والعليمي. يُنظر: ((تفسير الزمخشري)) (3/246)، ((تفسير النسفي)) (2/511)، ((تفسير العليمي)) (4/548). وممَّن اختار ما هو أعَمُّ مِن التقليبِ الحِسِّيِّ: ابنُ تيميَّةَ، والسعديُّ، وابنُ عثيمين: قال ابنُ عثيمين: (المرادُ ما هو أعَمُّ مِن التَّقليبِ الحِسِّيِّ، والتقليبُ الحِسِّيُّ أنَّ اللهَ يُقَلِّبُ الأرضَ: بَدلًا مِن أنْ كانت ضياءً ونهارًا إلى لَيلٍ، ثمَّ إلى نهارٍ، وهكذا... والتَّقليبُ المعنويُّ: ما يحصُلُ في هذه الأيامِ مِن الحوادِثِ والتغَيُّراتِ، والعِزِّ والنَّصرِ، والإذلالِ والخِذلانِ، كما قال الله تعالى: وَتِلْكَ الْأَيَّامُ نُدَاوِلُهَا بَيْنَ النَّاسِ
[آل عمران: 140]
). ((تفسير ابن عثيمين - سورة النور)) (ص: 301). وقال ابن تيميَّةَ: (تقليبُه اللَّيلَ والنَّهارَ: تحويلُ أحوالِ العالَمِ بإنزالِ المطَرِ الذي هو سبَبُ خلقِ النَّباتِ والحيوانِ والمَعدِن، وذلك سبَبُ تحويلِ النَّاسِ مِن حالٍ إلى حالٍ، المتضَمِّنِ رَفْعَ قومٍ وخَفْضَ آخَرينَ). ((مجموع الفتاوى)) (2/492). وقال السعدي: (يُقَلِّبُ اللَّهُ اللَّيْلَ وَالنَّهَارَ مِن حرٍّ إلى بردٍ، ومِن بردٍ إلى حرٍّ، مِن لَيلٍ إلى نهارٍ، ومِن نهارٍ إلى لَيلٍ، ويُديلُ الأيامَ بينَ عبادِه). ((تفسير السعدي)) (ص: 571).
